import React, { useContext } from "react";
import Pagination from "../Pagination/Pagination";
import Context from "../../context/context";
import Movie from "../Movie";

const SearchResult = () => {
    const ctx = useContext(Context);
    ctx.updateSearchResult({
        current_page: "1",
        total_pages: "1",
        movies: [
            {
                name: "interstellar",
                image: "https://images-na.ssl-images-amazon.com/images/I/71LNVGVpWYL._AC_SL1020_.jpg",
                genre: ["Adventure", "Drama", "Sci-Fi"],
                imdb_rating: "8.3",
            },
            {
                name: "Avengers: Endgame - Journey's End",
                image: "https://m.media-amazon.com/images/M/MV5BMTc5MDE2ODcwNV5BMl5BanBnXkFtZTgwMzI2NzQ2NzM@._V1_.jpg",
                genre: ["Adventure", "Drama", "Sci-Fi"],
                imdb_rating: "8.7",
            },
            {
                name: "Cruella",
                image: "https://image.tmdb.org/t/p/w780/hjS9mH8KvRiGHgjk6VUZH7OT0Ng.jpg",
                genre: ["Drama", "Action"],
                imdb_rating: "6.7",
            },
            {
                name: "interstellar",
                image: "https://images-na.ssl-images-amazon.com/images/I/71LNVGVpWYL._AC_SL1020_.jpg",
                genre: ["Adventure", "Drama", "Sci-Fi"],
                imdb_rating: "8.3",
            },
            {
                name: "Avengers: Endgame - Journey's End",
                image: "https://m.media-amazon.com/images/M/MV5BMTc5MDE2ODcwNV5BMl5BanBnXkFtZTgwMzI2NzQ2NzM@._V1_.jpg",
                genre: ["Adventure", "Drama", "Sci-Fi"],
                imdb_rating: "8.7",
            },
            {
                name: "Cruella",
                image: "https://image.tmdb.org/t/p/w780/hjS9mH8KvRiGHgjk6VUZH7OT0Ng.jpg",
                genre: ["Drama", "Action"],
                imdb_rating: "6.7",
            },
        ],
    });
    const generateMoviesList = () => {
        return ctx.searchResult.movies.map((item) => {
            return <Movie movie={item} key={item.imdb_id} />;
        });
    };
    return (
        <section class="searchResultsSection">
            <h5>
                Results of: <span class="searchQuery">"Results"</span>
            </h5>
            <ul class="searchResults hidden">{generateMoviesList()}</ul>
            <Pagination />
        </section>
    );
};

export default SearchResult;
